import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('intro'); // intro -> main

  useEffect(() => {
    // Stage 1: Professional Tracing & Reveal (4s)
    const timer = setTimeout(() => setStage('main'), 4500);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. PROFESSIONAL LOGO REVEAL */}
      <AnimatePresence>
        {stage === 'intro' && (
          <motion.div
            key="loader"
            className="fixed inset-0 flex items-center justify-center bg-[#fdfdfd] z-50"
            exit={{ opacity: 0, transition: { duration: 1, ease: "circOut" } }}
          >
            {/* Subtle radial glow behind the logo */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(11,57,84,0.03)_0%,_transparent_70%)]" />

            <div className="relative w-72 h-72 flex items-center justify-center">

              {/* THE ACTUAL LOGO IMAGE */}
              <motion.img 
                src="/logo.jpeg" 
                alt="CourseCraft Logo"
                className="w-full h-full object-contain"
                initial={{ opacity: 0, filter: "grayscale(100%) brightness(1.2)" }}
                animate={{ 
                  opacity: 1, 
                  filter: "grayscale(0%) brightness(1)",
                }}
                transition={{ delay: 1, duration: 2 }}
              />

              {/* THE TRACING OVERLAY (The "Professional" Mask) */}
              <svg className="absolute inset-0 w-full h-full" viewBox="0 0 100 100">
                {/* This path mimics the brain architecture to "draw" the reveal */}
                <motion.path
                  d="M50,85 C30,85 15,70 15,50 C15,30 30,15 50,15 C70,15 85,30 85,50 C85,60 80,75 70,85 L65,95 L55,85"
                  fill="none"
                  stroke="white" /* Matches the logo background to "wipe" it in */
                  strokeWidth="100" 
                  strokeDasharray="400"
                  initial={{ strokeDashoffset: 400 }}
                  animate={{ strokeDashoffset: 0 }}
                  transition={{ duration: 2.5, ease: "easeInOut" }}
                />
              </svg>

              {/* THE PLAY BUTTON HIGHLIGHT (Professional Glow) */}
              <motion.div 
                className="absolute w-12 h-12 bg-transparent rounded-full shadow-[0_0_30px_rgba(11,57,84,0.4)]"
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: [0, 1, 0.5], scale: [0.8, 1.2, 1] }}
                transition={{ delay: 3, duration: 1.5, repeat: Infinity }}
                style={{ top: '42%', left: '44%' }}
              />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN CONTENT (Refined & Modern) */}
      {stage === 'main' && (
        <motion.div 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          transition={{ duration: 1.5 }}
          className="relative"
        >
          {/* NAV BAR */}
          <nav className="fixed top-0 w-full h-24 px-12 flex items-center justify-between z-40 bg-white/60 backdrop-blur-xl border-b border-gray-50">
            <div className="flex items-center gap-4">
              <img src="/logo.jpeg" alt="Logo" className="h-10 w-auto mix-blend-multiply" />
              <span className="text-xl font-bold tracking-tight">CourseCraft</span>
            </div>
            <div className="flex gap-10 items-center">
              <button className="text-[10px] font-bold tracking-[0.2em] uppercase">Log In</button>
              <button className="px-8 py-3.5 bg-[#0B3954] text-white rounded-full text-[10px] font-bold tracking-[0.2em] uppercase shadow-2xl hover:bg-black transition-all">
                Get Started
              </button>
            </div>
          </nav>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center">
            <motion.div
               initial={{ y: 40, opacity: 0 }}
               animate={{ y: 0, opacity: 1 }}
               transition={{ delay: 0.3, duration: 1 }}
            >
              <h1 className="text-[8vw] leading-none font-medium tracking-tighter">
                Master any <br />
                <span className="italic font-light text-[#0B3954]">Skill.</span>
              </h1>
              <div className="mt-12 h-[1px] w-24 bg-[#0B3954] mx-auto opacity-20" />
              <p className="mt-8 text-sm tracking-[0.6em] uppercase text-gray-400">
                Precision Curated Learning
              </p>
            </motion.div>
          </section>

          {/* FEATURES */}
          <section className="bg-[#0B3954] py-40 overflow-hidden">
            <motion.div 
              className="flex gap-12 px-12"
              animate={{ x: [0, -1200] }}
              transition={{ duration: 40, repeat: Infinity, ease: "linear" }}
            >
              {[...Array(2)].map(() => (
                <div className="flex gap-12">
                  {[
                    { t: "Neural Curation", d: "AI-mapped learning paths." },
                    { t: "Deep Summary", d: "Core concepts, distilled." },
                    { t: "Active Recall", d: "Smart quiz injection." }
                  ].map((item, idx) => (
                    <div key={idx} className="w-[450px] aspect-video border border-white/10 rounded-2xl p-12 flex flex-col justify-end hover:bg-white/5 transition-colors">
                      <h3 className="text-white text-3xl font-light mb-4">{item.t}</h3>
                      <p className="text-white/40 text-lg leading-relaxed">{item.d}</p>
                    </div>
                  ))}
                </div>
              ))}
            </motion.div>
          </section>

          <footer className="py-20 text-center text-[10px] tracking-widest text-gray-300 uppercase">
            © 2026 — CourseCraft AI Studio
          </footer>
        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
